import type { NextRequest } from 'next/server'

export function middleware(request: NextRequest) {
  const { method, nextUrl, headers } = request
  const url = nextUrl.pathname + nextUrl.search
  const timestamp = new Date().toISOString()
  const userAgent = headers.get('user-agent') || 'unknown'

  console.log(`[${timestamp}] ${method} ${url}`)
  console.log(`  → User-Agent: ${userAgent}`)

  // Get the response so we can also log its status
  const response = NextResponse.next()

  // Monkey-patch the Response to capture the status
  // (available via response.status after Next.js processes it)
  console.log(`  ← Response generated`)

  return response
}

export const config = {
  matcher: [
    /*
     * Match all request paths except:
     * - _next/static (static files)
     * - _next/image (image optimization)
     * - favicon.ico (browser favicon)
     * - images, fonts, etc.
     */
    '/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp|woff2?)$).*)',
  ],
}
"}

