import type { NextRequest } from 'next/server'

export function middleware(request: NextRequest) {
  const { method, nextUrl, headers } = request
  const url = nextUrl.pathname + nextUrl.search
  const timestamp = new Date().toISOString()
  const userAgent = headers.get('user-agent')?.split('/')[0] ?? 'unknown'
  const referer = headers.get('referer') ?? undefined

  const start = performance.now()

  const response = NextResponse.next()

  // Log after the response is sent (via waitUntil pattern)
  response.headers.set('x-request-timing', String(start))

  console.log(
    `[${timestamp}] ${method} ${url}` +
      (referer ? ` (from: ${new URL(referer).pathname})` : '')
  )
  console.log(`  › UA: ${userAgent} | Duration: ${(performance.now() - start).toFixed(1)}ms`)

  return response
}

